import React from "react";
import { Box, Button, Grid, TextField, Typography } from "@mui/material";

type ButtonInputProps = {
    value: string;
    onChange: (v: string) => void;
    onClick?: (v: string) => void;
    mask?: (str: string) => string;
    error?: boolean;
    helperText?: string;
    label: string;
    buttonLabel: string;
    width?: string;
}

const ButtonInput = ({ value, onChange, onClick, mask, error, helperText, label, buttonLabel, width }: ButtonInputProps) => {

    const handleButtonInput = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (mask) onChange(mask(e.target.value));
        else onChange(e.target.value)
    }

    return (
        <Box width={width || '100%'}>
            <Typography variant="overline">
                {label}
            </Typography>
            <Box width='100%'>
                <TextField
                    hiddenLabel
                    style={{ width: 'calc(100% - 120px)' }}
                    InputProps={{
                        disableUnderline: true, sx: {
                            height: 48,
                            ...(error ? { border: '1px solid red' } : {}),
                        }
                    }
                    }
                    variant="filled"
                    value={value}
                    error={true}
                    helperText={helperText}
                    onChange={handleButtonInput}
                />
                <Button
                    variant="contained"
                    onClick={() => { if (onClick) onClick(value) }}
                    sx={{ width: '120px', height: 48 }}
                >
                    {buttonLabel}
                </Button>
            </Box>
        </Box>
    )
}

export default ButtonInput;

